#  YORDAMCHI FUNKSIYALAR
# ──────────────────────────────────────────────────────────────────────────

def parse_date(s):
    if not s:
        return None
    return datetime.strptime(s.strip(), '%Y-%m-%d').date()


def to_decimal(v):
    if v is None:
        return Decimal('0')
    return Decimal(str(v))


STATUS_MAP = {
    'faol': 'faol',
    'tugagan': 'tugagan',
    'topshirildi': 'tugagan',   # qaytarib berilgan / yopilgan hujjat -> tugagan
    'qarzli': 'qarzli',
}


def map_status(raw_status):
    return STATUS_MAP.get(raw_status, 'faol')


def make_kirim(drv, tur, summa, doc):
    """driver_documents'dagi paid_amount asosida TolovQayd (Kirim) yozuvi yaratadi.
    To'lov sanasi sifatida hujjat yangilangan sanasi (agar to'liq to'langan bo'lsa)
    yoki yaratilgan sanasi ishlatiladi -- bu eng yaqin taxmin, chunki manba
    bazasida alohida to'lovlar tarixi saqlanmagan, faqat joriy summalar bor."""
    if summa <= 0:
        return False
    debt = doc.get('debt_amount') or 0
    ts = doc.get('updated_at') if debt == 0 else doc.get('created_at')
    ts = ts or doc.get('created_at')
    sana = parse_date(ts.split(' ')[0]) if ts else date.today()
    TolovQayd.objects.get_or_create(
        driver=drv, tur=tur, summa=summa, sana=sana,
        izoh=f"SQL importdan ({tur}, hujjat ID {doc.get('id')})",
    )
    return True


