print('1) Haydovchilarni import qilish...')
print('=' * 60)

profiles_by_user = {p['user_id']: p for p in DRIVER_PROFILES}

# user_id (Laravel) -> Driver instance (Django)
driver_map = {}

created_count = 0
existing_count = 0

for u in USERS:
    if u['role'] != 'driver':
        continue  # admin foydalanuvchini o'tkazib yuboramiz

    uid = u['id']
    profile = profiles_by_user.get(uid, {})

    ism = u['name'] or f'Haydovchi {uid}'
    telefon = profile.get('phone') or ''
    mashina = profile.get('car_name') or ''
    raqam = profile.get('car_number') or ''
    pasport_seriya = profile.get('passport') or ''
    parol = f'driver{uid}'

    drv = Driver.objects.filter(parol=parol).first()
    if drv:
        existing_count += 1
    else:
        drv = Driver.objects.create(
            ism=ism,
            telefon=telefon,
            mashina=mashina,
            raqam=raqam,
            pasport_seriya=pasport_seriya,
            parol=parol,
        )
        created_count += 1

    driver_map[uid] = drv

print(f'  Yangi yaratildi: {created_count}')
print(f'  Mavjud edi: {existing_count}')
print(f'  Jami haydovchilar (xaritada): {len(driver_map)}')


# ──────────────────────────────────────────────────────────────────────────
#  2) HUJJATLARNI YARATISH (driver_documents -> Putyovka / TIR / Dazvol / IjaraShartnoma)
# ──────────────────────────────────────────────────────────────────────────

print()
print('=' * 60)
print('2) Hujjatlarni import qilish...')
print('=' * 60)

stats = {
    'putyovka': [0, 0],
    'tir': [0, 0],
    'dazvol': [0, 0],
    'rent': [0, 0],
    'license': [0, 0],
    'skipped': 0,
}

for doc in DRIVER_DOCUMENTS:
    uid = doc['user_id']
    drv = driver_map.get(uid)
    if drv is None:
        # Bu hujjat egasi (driver) topilmadi -- o'tkazib yuboramiz
        stats['skipped'] += 1
        continue

    boshlanish = parse_date(doc['start_date'])
    tugash = parse_date(doc['end_date'])
    narxi = to_decimal(doc['price'])
    tolangan = to_decimal(doc.get('paid_amount'))
    status = map_status(doc['status'])
    shifr = doc.get('shifr') or ''
    izoh = doc.get('comment') or ''

    doc_type = doc['type']

    if doc_type == 'putyovka':
        obj, created = Putyovka.objects.get_or_create(
            driver=drv, shifr=shifr, boshlanish=boshlanish,
            defaults=dict(
                raqam='', narxi=narxi, tolangan=tolangan,
                muddat=12, tugash=tugash, status=status, izoh=izoh,
            )
        )
        stats['putyovka'][0 if created else 1] += 1
        if created:
            make_kirim(drv, 'putyovka', tolangan, doc)

    elif doc_type == 'tir':
        obj, created = TIR.objects.get_or_create(
            driver=drv, tir_raqam=shifr or f'TIR-{doc["id"]}', boshlanish=boshlanish,
            defaults=dict(
                narxi=narxi, tolangan=tolangan, muddat=3,
                tugash=tugash, status=status, izoh=izoh,
            )
        )
        stats['tir'][0 if created else 1] += 1
        if created:
            make_kirim(drv, 'tir', tolangan, doc)

    elif doc_type == 'dazvol':
        obj, created = Dazvol.objects.get_or_create(
            driver=drv, dazvol_raqam=shifr, boshlanish=boshlanish,
            defaults=dict(
                mamlakat="Noma'lum", narxi=narxi, tolangan=tolangan,
                tugash=tugash, status=status, izoh=izoh,
            )
        )
        stats['dazvol'][0 if created else 1] += 1
        if created:
            make_kirim(drv, 'dazvol', tolangan, doc)

    elif doc_type == 'rent':
        obj, created = IjaraShartnoma.objects.get_or_create(
            driver=drv, manzil=shifr or f'Ijara-{doc["id"]}', boshlanish=boshlanish,
            defaults=dict(
                narxi=narxi, tolangan=tolangan,
                tugash=tugash,
                status='faol' if status != 'tugagan' else 'tugagan',
                izoh=izoh,
            )
        )
        stats['rent'][0 if created else 1] += 1
        if created:
            make_kirim(drv, 'ijara', tolangan, doc)

    elif doc_type == 'license':
        obj, created = Litsenziya.objects.get_or_create(
            driver=drv, litsenziya_raqam=shifr or f'LIC-{doc["id"]}', boshlanish=boshlanish,
            defaults=dict(
                narxi=narxi, tolangan=tolangan,
                tugash=tugash,
                status='faol' if status != 'tugagan' else 'tugagan',
                izoh=izoh,
            )
        )
        stats['license'][0 if created else 1] += 1
        if created:
            make_kirim(drv, 'litsenziya', tolangan, doc)

    else:
        stats['skipped'] += 1

