# ──────────────────────────────────────────────────────────────────────────
#  3) CHIQIMLARNI YARATISH (driver_expenses -> Chiqim)
# ──────────────────────────────────────────────────────────────────────────

print()
print('=' * 60)
print('3) Chiqimlarni import qilish...')
print('=' * 60)

EXPENSE_TYPE_MAP = {
    'yoqilgi': 'xizmat',
    'taom': 'boshqa',
    'maosh': 'maosh',
    'ta_mir': 'ta_mir',
}

exp_created = 0
exp_existing = 0

for e in DRIVER_EXPENSES:
    uid = e['user_id']
    drv = driver_map.get(uid)
    sana = parse_date(e['expense_date'])
    summa = to_decimal(e['amount'])
    tur = EXPENSE_TYPE_MAP.get(e['type'], 'boshqa')
    izoh_parts = []
    if e.get('comment'):
        izoh_parts.append(e['comment'])
    izoh_parts.append(f"[{e['type']}]")
    izoh = ' '.join(izoh_parts)

    obj, created = Chiqim.objects.get_or_create(
        driver=drv, summa=summa, sana=sana, izoh=izoh,
        defaults=dict(tur=tur)
    )
    if created:
        exp_created += 1
    else:
        exp_existing += 1

print(f'  Yangi yaratildi: {exp_created}')
print(f'  Mavjud edi: {exp_existing}')

